const url = $node.Webhook.json.body.url || '';
let html = '';
const raw = $input.first().json;
if (typeof raw === 'string') html = raw;
else if (typeof raw.data === 'string') html = raw.data;
else if (raw.body && typeof raw.body === 'string') html = raw.body;
else html = JSON.stringify(raw);

if (!html || html.length < 50) {
  return [{json: {error: 'صفحه قابل دریافت نبود یا خالی بود.', url: url}}];
}

// Isolate body
let body = html;
const bm = html.match(/<body[^>]*>([\s\S]*?)<\/body>/i);
if (bm) body = bm[1];
// Remove non-content tags
const clean = body.replace(/<(script|style|noscript|svg|template|nav|footer|header)[^>]*>[\s\S]*?<\/\1>/gi, ' ');
// Strip tags -> text
let text = clean.replace(/<[^>]+>/g, ' ').replace(/&[a-z#0-9]+;/gi, ' ').replace(/\s+/g, ' ').trim();
const words = text ? text.split(/\s+/).filter(Boolean) : [];
const wordCount = words.length;

// Headings
function grab(tag){ const re = new RegExp('<'+tag+'\\b[^>]*>([\\s\\S]*?)<\\/'+tag+'>','gi'); const out=[]; let m; while((m=re.exec(html))!==null){ const t=m[1].replace(/<[^>]+>/g,'').replace(/\s+/g,' ').trim(); if(t) out.push(t.slice(0,120)); } return out; }
const h1 = grab('h1'), h2 = grab('h2'), h3 = grab('h3');

// Images
const imgs = html.match(/<img\b[^>]*>/gi) || [];
let noAlt = 0; imgs.forEach(t => { if(!/\balt\s*=\s*["'][^"']+["']/i.test(t)) noAlt++; });

// Links
let host=''; try { host = new URL(url).hostname.replace(/^www\./,''); } catch(e){}
const anchors = html.match(/<a\b[^>]*href\s*=\s*["']([^"']+)["']/gi) || [];
let internal=0, external=0;
anchors.forEach(a => { const hm=a.match(/href\s*=\s*["']([^"']+)["']/i); if(!hm) return; const href=hm[1]; if(href.startsWith('#')||/^javascript:/i.test(href)) return; let h=''; try{ h=new URL(href, url).hostname.replace(/^www\./,''); }catch(e){} if(!h||h===host) internal++; else external++; });

// Title + meta
const tm = html.match(/<title[^>]*>([\s\S]*?)<\/title>/i);
const title = tm ? tm[1].replace(/<[^>]+>/g,'').trim() : '';
let metaDesc=''; const dm = html.match(/<meta[^>]+name\s*=\s*["']description["'][^>]*content\s*=\s*["']([^"']*)["']/i) || html.match(/<meta[^>]+content\s*=\s*["']([^"']*)["'][^>]*name\s*=\s*["']description["']/i); if(dm) metaDesc = dm[1].trim();

// Schema
const schemaSet = new Set(); let sm; const sre=/"@type"\s*:\s*"([^"]+)"/gi; while((sm=sre.exec(html))!==null){ schemaSet.add(sm[1]); }
const schema = Array.from(schemaSet).slice(0,10);

// Paragraphs
const paragraphs = (html.match(/<p\b[^>]*>/gi) || []).length;

// Score
let score = Math.min(50, Math.round(wordCount/30)) + (h1.length>=1?10:0) + Math.min(20,h2.length*3) + Math.min(10,h3.length*2) + Math.min(10,imgs.length*2);
score = Math.min(100, score);

return [{json: {
  url: url,
  word_count: wordCount,
  h1: h1.length, h2: h2.length, h3: h3.length,
  h1_texts: h1.slice(0,3), h2_texts: h2.slice(0,12),
  images: imgs.length, images_no_alt: noAlt,
  internal_links: internal, external_links: external,
  title: title, meta_desc: metaDesc,
  schema: schema, paragraphs: paragraphs,
  word_count_score: score
}}];
